import * as t from "io-ts";
import { optionalString } from "../../../utils";

export const TokenRecipientEntryItem = t.intersection([
  t.type({
    tokenQuantity: t.string,
    tokenType: t.string,
  }),
  t.partial({
    tokenId: optionalString,
  }),
]);

export type TokenRecipientEntryItem = t.TypeOf<typeof TokenRecipientEntryItem>;
